import os
import queue
import random
import threading


class MicroserviceConnectionPool:
  def __init__(self, service_name, service_client_class, servers, pool_max_size, logger):
    self._service_name = service_name
    self._service_client_class = service_client_class
    self._servers = servers
    self._pool_max_size = pool_max_size
    self._logger = logger
    self._conn_pool = queue.Queue()
    self._conn_pool_lock = threading.Lock()
    self._pool_size = 0

  def get_client(self):
    if self._pool_max_size == 0:
      server_address = random.choice(self._servers)
      conn = self._service_client_class(server_address.split(':')[0], int(server_address.split(':')[1]),
          logger=self._logger, connection_pool=self)
    else:
      if self._pool_size < self._pool_max_size:
        with self._conn_pool_lock:
          if self._pool_size < self._pool_max_size:
            server_address = self._servers[self._pool_size % len(self._servers)]
            self._conn_pool.put(self._service_client_class(server_address.split(':')[0],
                int(server_address.split(':')[1]), logger=self._logger, connection_pool=self))
            self._pool_size += 1
      conn = self._conn_pool.get(block=True, timeout=None)
    return conn

  def release_client(self, conn):
    if self._pool_max_size == 0:
      conn.close()
    else:
      self._conn_pool.put(conn)
